// --- Config ---
const SUBDOMAIN   = "infodvnlogcom";
const PIPELINE_ID = 11613083;
const STATUS_ID   = 89191851;
const RESPONSIBLE_USER_ID = 12924735;

// --- Fixed Tags ---
const FIXED_TAGS = [{ name: "MonthlyTax" }];

// --- Helpers ---
const isNonEmpty = v => v != null && String(v).trim() !== "";
const toStr = v => (v == null ? "" : String(v)).trim();

const pickFirst = (...candidates) => {
  for (const c of candidates.flat()) {
    if (Array.isArray(c)) continue; // نتجنب المصفوفات هنا
    if (isNonEmpty(c)) return String(c).trim();
  }
  return "";
};

const uniq = arr => [...new Set(arr.filter(isNonEmpty))];

// إزالة المسافات/الشرط/الأقواس مع الإبقاء على +
const normalizePhone = p => toStr(p).replace(/[^\d+]+/g, "");

// اجمع حتى 5 أرقام من حقول phone_1..phone_5 أو مصادر بديلة
function collectPhones(src = {}) {
  const fromFixed = [1,2,3,4,5].map(i => toStr(src[`phone_${i}`]));
  const fromArray = Array.isArray(src.phone_values) ? src.phone_values.map(toStr) : [];
  const contactPhone = toStr(src.contact_phone);

  const all = uniq([...fromFixed, ...fromArray, contactPhone]).map(normalizePhone);
  return all.slice(0, 5);
}

// اجمع حتى 5 إيميلات من email_1..email_5 أو مصادر بديلة
function collectEmails(src = {}) {
  const fromFixed = [1,2,3,4,5].map(i => toStr(src[`email_${i}`]).toLowerCase());
  const fromArray = Array.isArray(src.email_values) ? src.email_values.map(e => toStr(e).toLowerCase()) : [];
  const contactEmail = toStr(src.contact_email).toLowerCase();

  const all = uniq([...fromFixed, ...fromArray, contactEmail]);
  return all.slice(0, 5);
}

function createCustomFieldsValues(phones, emails) {
  const arr = [];
  if (phones.length) {
    arr.push({
      field_code: "PHONE",
      values: phones.map(p => ({ value: p, enum_code: "WORK" }))
    });
  }
  if (emails.length) {
    arr.push({
      field_code: "EMAIL",
      values: emails.map(e => ({ value: e, enum_code: "WORK" }))
    });
  }
  return arr;
}

// استخراج/بناء first/last/full name من سجل
function deriveNames(rec = {}) {
  const full =
    pickFirst(rec.full_name, rec.contact_name) ||
    `${toStr(rec.first_name)} ${toStr(rec.last_name)}`.trim();

  let first = toStr(rec.first_name);
  let last  = toStr(rec.last_name);

  if (!first && !last && full) {
    const parts = full.trim().split(/\s+/);
    first = parts[0] || "";
    last  = parts.length > 1 ? parts.slice(1).join(" ") : "";
  }
  return {
    first_name: first,
    last_name : last,
    full_name : full
  };
}

// تكوين اسم الشركة مع فول-باك ذكي من folder_name (إزالة TAX من البداية)
function deriveCompanyName(rec = {}) {
  const direct = pickFirst(rec.company_name, rec.companyName);
  if (direct) return direct;
  const folder = toStr(rec.folder_name || rec.folderName);
  return folder.replace(/^TAX\s+/i, "").trim();
}

// تجميع التاجز من عدة مصادر (+ dedupe)
function collectTags(records = []) {
  const out = new Set();

  const add = (name) => {
    const n = toStr(name);
    if (!n) return;
    out.add(n.toLowerCase()); // لمنع التكرار case-insensitive
  };

  for (const r of records) {
    // arrays مباشرة
    if (Array.isArray(r.tags)) r.tags.forEach(add);
    if (isNonEmpty(r.tag_name)) add(r.tag_name);

    // tag_objects: [{id,name}]
    if (Array.isArray(r.tag_objects)) {
      r.tag_objects.forEach(o => add(o?.name));
    }

    // لو كانت موجودة داخل documents[0].tags
    if (Array.isArray(r.documents?.[0]?.tags)) {
      r.documents[0].tags.forEach(add);
    }
  }

  // حوّلها لشكل [{name}]
  return [...out].map(n => ({ name: n }));
}

// دمج التاجز الثابتة مع الديناميكية مع منع التكرار
function mergeFixedAndDynamicTags(dynamic = []) {
  const all = [...FIXED_TAGS, ...dynamic];
  const seen = new Set();
  const res = [];
  for (const t of all) {
    const key = toStr(t.name).toLowerCase();
    if (!key || seen.has(key)) continue;
    seen.add(key);
    res.push({ name: t.name });
  }
  return res;
}

// --- Builder ---
return $input.all().map(item => {
  const d = item.json || {};

  // مصدر السجلات التفصيلي داخل كل فولدر
  const records = Array.isArray(d.all_records) && d.all_records.length ? d.all_records : [d];

  // خُذ أول سجل صالح كمرجع للاسم/الشركة/الاتصال
  const base = records[0] || {};

  // أسماء
  const { first_name, last_name, full_name } = deriveNames(base);

  // شركة
  const companyName = deriveCompanyName(base);

  // تليفونات وإيميلات (نفضل الجمع من كل السجلات داخل نفس الفولدر)
  const allPhones  = uniq(records.flatMap(r => collectPhones(r))).slice(0, 5);
  const allEmails  = uniq(records.flatMap(r => collectEmails(r))).slice(0, 5);

  // تاجز ديناميكية + ثابتة (MonthlyTax)
  const dynamicTags = collectTags(records);
  const tagsArray   = mergeFixedAndDynamicTags(dynamicTags);

  // بناء الـ payload مع الحفاظ على نفس الهيكلة المطلوبة
  return {
    method: "POST",
    url: `https://${SUBDOMAIN}.kommo.com/api/v4/leads/complex`,
    payload: {
      name: full_name,                          // اسم الـ Lead = الاسم الكامل
      pipeline_id: PIPELINE_ID,
      status_id: STATUS_ID,
      responsible_user_id: RESPONSIBLE_USER_ID,
      created_by: RESPONSIBLE_USER_ID,
      _embedded: {
        tags: tagsArray,                        // [{ name }] يحتوي MonthlyTax + ديناميكي بدون تكرار
        companies: [{ name: companyName }],     // شركة واحدة بالاسم
        contacts: [
          {
            first_name,
            last_name,
            name: full_name,
            custom_fields_values: createCustomFieldsValues(allPhones, allEmails)
          }
        ]
      }
    }
  };
});

// ===== Helpers =====
function normalizeText(text) {
  if (!text) return "";
  return String(text)
    // remove zero-width & RTL marks
    .replace(/[\u200B-\u200F\u061C]/g, "")
    // NFKD + strip diacritics
    .normalize("NFKD").replace(/[\u0300-\u036f]/g, "")
    // Turkish casing quirks
    .replace(/İ/g, "i").replace(/ı/g, "i")
    // unify spaces & lowercase
    .toLowerCase().replace(/\s+/g, " ").trim();
}

function stripTaxPrefix(name) {
  const n = normalizeText(name);
  return n.replace(/^tax\s+/, "").trim();
}

function companyKey(obj) {
  // جرّب companyName/ company_name
  const byCompany = normalizeText(obj.company_name || obj.companyName || "");
  if (byCompany) return byCompany;
  // وإلا استخرج من اسم الفولدر بدون TAX
  return stripTaxPrefix(obj.folder_name || obj.folderName || "");
}

// ===== Read all =====
const all = $input.all().map(x => x.json);

// refs = العناصر اللي فيها IDs (الـ 8)
const refs = all.filter(r => r.lead_id != null || r.company_id != null);

// base = العناصر المطلوب إخراجها (الـ 15)
const base = all.filter(r => (r.lead_id == null && r.company_id == null));

// فهرس بالـ folderId
const byFolderId = new Map();
for (const r of refs) {
  const fid = r.folder_Id || r.folderId;
  if (fid && !byFolderId.has(fid)) byFolderId.set(fid, r);
}

// فهرس باسم الشركة الموحّد
const byCompany = new Map();
for (const r of refs) {
  const key = companyKey(r);
  if (key && !byCompany.has(key)) byCompany.set(key, r);
}

// ===== Enrich only the 15 base records =====
const out = base.map(row => {
  let lead_id      = row.lead_id ?? null;
  let company_id   = row.company_id ?? null;
  let company_name = row.company_name || row.companyName || null;
  let folder_name  = row.folder_name  || row.folderName  || null;
  let folder_Id    = row.folder_Id    || row.folderId    || null;

  let ref = null;
  let note = "";

  // 1) مطابقة بالـ folder_Id
  if (folder_Id && byFolderId.has(folder_Id)) {
    ref = byFolderId.get(folder_Id);
    note = "matched by folder_Id";
  }

  // 2) وإلا مطابقة باسم الشركة بعد التطبيع
  if (!ref) {
    const key = companyKey(row);
    if (key && byCompany.has(key)) {
      ref = byCompany.get(key);
      note = "matched by company name";
    }
  }

  if (ref) {
    if (lead_id == null)     lead_id    = ref.lead_id    ?? lead_id;
    if (company_id == null)  company_id = ref.company_id ?? company_id;
    if (!company_name)       company_name = ref.company_name || ref.companyName || company_name;
    if (!folder_name)        folder_name  = ref.folder_name  || ref.folderName  || folder_name;
    if (!folder_Id)          folder_Id    = ref.folder_Id    || ref.folderId    || folder_Id;
  } else {
    note = "no match found (check folderId / company name normalization)";
  }

  return {
    json: {
      ...row,
      lead_id,
      company_id,
      company_name: company_name ?? null,
      folder_name: folder_name ?? null,
      folder_Id: folder_Id ?? null,
      match_note: note
    }
  };
});

return out;

return items.map(item => {
  try {
    const rawData = item.json.data;

    if (!rawData) return { json: { error: 'No data' } };

    const parsed = JSON.parse(rawData);
    const lead = parsed._embedded?.leads?.[0];

    if (!lead) return { json: { error: 'No lead found' } };

    const phoneQuery = parsed._links?.self?.href?.match(/query=([^&]+)/)?.[1] || null;

    const tags = lead._embedded?.tags || [];

    return {
