        lead_id: lead.id,
        lead_name: lead.name,
        phone_query: decodeURIComponent(phoneQuery || ''),
        company_id: lead._embedded?.companies?.[0]?.id || null,
        tags: tags.map(tag => tag.name),
        tag_ids: tags.map(tag => tag.id),
        tag_objects: tags
      }
    };
  } catch (e) {
    return { json: { error: e.message } };
  }
});

return items.map(item => {
  try {
    const raw = item.json.data;
    if (!raw) return { json: { error: 'No data' } };

    const parsed = JSON.parse(raw);
    const contact = parsed._embedded?.contacts?.[0];

    if (!contact) return { json: { error: 'No contact found' } };

    // استخراج أرقام الهاتف
    const phone_values = contact.custom_fields_values?.find(f => f.field_code === 'PHONE')?.values?.map(v => v.value) || [];

    // استخراج الإيميلات
    const email_values = contact.custom_fields_values?.find(f => f.field_code === 'EMAIL')?.values?.map(v => v.value) || [];

    return {
      json: {
        contact_id: contact.id,
        contact_name: contact.name,
        phone_values,
        email_values,
        tags: contact._embedded?.tags?.map(tag => tag.name) || [],
        company_id: contact._embedded?.companies?.[0]?.id || null
      }
    };
  } catch (e) {
    return { json: { error: e.message } };
  }
});

// خُد كل العناصر من النود السابقة
const items = $input.all();

// لو مفيش payload في أي عنصر، مرر الداتا زي ما هي (ما توقفش الفلو)
const payloadItem = items.find(i => i.json && i.json.payload);
if (!payloadItem) {
  return items; // مهم: ما نرجعش [] عشان المسار مايقفش
}

// استخرج بيانات الهدف من الـ payload
const payload = payloadItem.json.payload;

const targetName =
  payload?.name || "";

const targetEmail =
  payload?._embedded?.contacts?.[0]?.custom_fields_values
    ?.find(f => f.field_code === "EMAIL")
    ?.values?.[0]?.value || "";

const targetCompany =
  payload?._embedded?.companies?.[0]?.name || "";

// دالة لتوحيد المقارنة (lower/trim)
const norm = (v) => (v || "").toString().trim().toLowerCase();

let mergedDone = false;

// هنمشي على العناصر، وأول واحد يطابق (بالاسم+الإيميل+الشركة) ندمجه مع الـ payload
const out = items.map(i => {
  if (i === payloadItem) return i; // سيب عنصر الـ payload زي ما هو مؤقتًا

  const j = i.json;

  const name = j.contact_name || j.full_name || j.lead_name || "";
  const email = j.contact_email || (Array.isArray(j.email_values) ? j.email_values[0] : j.email) || "";
  const company = j.company_name || j.companyName || "";

  const isMatch =
    norm(name) === norm(targetName) &&
    norm(email) === norm(targetEmail) &&
    norm(company) === norm(targetCompany);

  if (!isMatch || mergedDone) return i;

  mergedDone = true;

  // حضّر مصفوفات IDs لو متوفرة
  const leadIds = [...new Set([...(j.leadIds || []), j.lead_id].filter(Boolean))];
  const contactIds = [...new Set([...(j.contactIds || []), j.contact_id].filter(Boolean))];

  return {
    json: {
      ...j,
      payload,            // خليه معاك لو محتاجه لاحقًا
      leadIds,
      contactIds,
      matchType: j.matchType || "Both", // أو غيّرها حسب لوجيكك
    }
  };
});

// لو مفيش ولا عنصر اتدمج، ممكن تختار تضيف عنصر بيوثّق payload لوحده (اختياري)
if (!mergedDone) {
  out.push({ json: { payload, matchType: "payload_only" } });
}

return out;

// ===== Helpers =====
const splitMultiPhones = (value) =>
  String(value || '')
    .split(/[,،;\/]+/g)              // نفصل لو في أكتر من رقم
    .map(s => s.trim())
    .filter(Boolean);

const extractEmails = (value) =>
  String(value || '')
    .split(/[,،;\/\s]+/g)            // الإيميلات ممكن تتفصل بمسافات
    .map(s => s.trim())
    .filter(Boolean);

const normalizePhone = (raw) => {
  if (!raw) return '';
  let p = String(raw).trim();
  p = p.replace(/^00/, '+');         // 00.. -> +
  p = p.replace(/[^\d+]/g, '');      // اسمح بالأرقام و + فقط
  const plusCount = (p.match(/\+/g) || []).length;
  if (plusCount > 1) {
    let seen = false;
    p = p.split('').filter(ch => {
      if (ch === '+') { if (seen) return false; seen = true; }
      return true;
    }).join('');
  }
  return p;
};

const normalizeEmail = (e) => String(e || '').toLowerCase().trim();
const normText = (t) => String(t || '').toLowerCase().replace(/\s+/g, ' ').trim();

// ===== Build map per contact inside same folder/company =====
const map = new Map();

for (const item of items) {
  const row = item.json;

  const folderName = row.folderName || row.folder_name || '';
  const folderId   = row.folderId   || row.folder_Id   || '';
  const company    = row.companyName || row.company_name || '';
  const fullName   = row.full_name || row.contact_name || '';

  const key = `${normText(fullName)}|${normText(folderName || company)}`;

  // تليفونات من contact_phone (قد يحتوي عدة أرقام)
  const phoneCandidates = [];
  if (row.contact_phone) phoneCandidates.push(...splitMultiPhones(row.contact_phone));

  // لو موجود phone_1..phone_5 بنجمعهم كرقم واحد
  const splitParts = [row.phone_1, row.phone_2, row.phone_3, row.phone_4, row.phone_5]
    .map(x => (x == null ? '' : String(x).trim()))
    .filter(Boolean);
  if (splitParts.length) phoneCandidates.push(splitParts.join(' '));

  const normPhones = phoneCandidates.map(normalizePhone).filter(Boolean);

  // الإيميلات من contact_email + email_1..email_5
  const emailCandidates = [];
  if (row.contact_email) emailCandidates.push(...extractEmails(row.contact_email));
  for (let i = 1; i <= 5; i++) {
    if (row[`email_${i}`]) emailCandidates.push(row[`email_${i}`]);
  }
  const normEmails = emailCandidates.map(normalizeEmail).filter(Boolean);

  if (!map.has(key)) {
    map.set(key, {
      contact_name: fullName || '',
      company_name: company || '',
      folder_name: folderName || '',
      folder_Id: folderId || '',
      phones: new Set(normPhones),
      emails: new Set(normEmails),
      batch_date: row.batchDate || row.batch_date || '',
      batch_time: row.batchtime || row.batch_time || ''
    });
  } else {
    const ex = map.get(key);
    normPhones.forEach(p => ex.phones.add(p));
    normEmails.forEach(e => ex.emails.add(e));
  }
}

// ===== Flatten to output: keep ONLY first phone, emails up to 5 =====
const out = [];
for (const entry of map.values()) {
  // رتّب الأرقام وخد الأول فقط
  const phones = Array.from(entry.phones).sort((a, b) => b.length - a.length);
  const firstPhone = phones[0] || '';

  // الإيميلات (حتى 5 كما هي)
  const emails = Array.from(entry.emails).slice(0, 5);

  // الاستعلام الأساسي يفضّل الهاتف الأول
  let primary_query_type = '';
  let primary_query_value = '';
  if (firstPhone) {
    primary_query_type = 'phone';
    primary_query_value = firstPhone;
  } else if (emails[0]) {
    primary_query_type = 'email';
    primary_query_value = emails[0];
  }

  // حقول الهاتف: فقط phone_1 إن وجد
  const phoneFields = {};
  if (firstPhone) phoneFields.phone_1 = firstPhone;

  // حقول الإيميل: ديناميكيًا بدون فراغات
  const emailFields = {};
  emails.forEach((e, idx) => { emailFields[`email_${idx+1}`] = e; });

  out.push({
    json: {
      contact_name: entry.contact_name,
      company_name: entry.company_name,
      folder_name: entry.folder_name,
      folder_Id: entry.folder_Id,
      ...phoneFields,                // فقط phone_1 لو موجود
      ...emailFields,                // email_1..email_n الموجودين فقط
      primary_query_type,
      primary_query_value,
      batch_date: entry.batch_date,
      batch_time: entry.batch_time
    }
  });
}

return out;

