  const phoneField = cf.find(f => f.field_code === 'PHONE');
  return phoneField?.values?.[0]?.value || '';
};

// ===== targets (خلّيها فاضية لو مش عايز تقيّد بيها) =====
const targetName    = "doaa yousri";          // جرّب سيبها فاضية ""
const targetEmail   = "adel.mhmad@gmail.com"; // جرّب سيبها فاضية ""
const targetCompany = "A BAHARI OTOMOTİV";    // جرّب سيبها فاضية ""
// مثال بديل للبحث بالموبايل فقط:
// const targetPhone = "+905316713665";

const tName = norm(targetName);
const tEmail = norm(targetEmail);
const tCompany = norm(targetCompany);
// const tPhone = norm(targetPhone);

const out = items.filter(item => {
  const d = item.json;
  if (!d?.payload) return false;

  const name    = norm(d.payload.name);
  const email   = norm(getEmail(d));
  const company = norm(d.payload?._embedded?.companies?.[0]?.name);
  // const phone   = norm(getPhone(d));

  let ok = true;
  if (tName)    ok = ok && (name === tName);
  if (tEmail)   ok = ok && (email === tEmail);
  if (tCompany) ok = ok && (company === tCompany);
  // لو هتستخدم الموبايل:
  // if (tPhone)   ok = ok && (phone === tPhone);

  return ok;
});

return out;

const map = new Map();

for (const item of items) {
  const json = item.json;

  const folderName = json.folder_name || 'no_folder';
  const key = folderName; // مفتاح الدمج

  // تقسيم الاسم
  let firstName = "";
  let lastName = "";
  let fullName = json.contact_name?.trim() || "";

  if (fullName) {
    const parts = fullName.split(/\s+/);
    firstName = parts[0] || "";
    lastName = parts.length > 1 ? parts.slice(1).join(" ") : "";
  }

  // تجهيز بيانات العنصر
  const entry = {
    ...json,
    lead_id: json.lead_id || null,
    contact_id: json.contact_id || null,
    first_name: firstName,
    last_name: lastName,
    full_name: fullName,
    matchType: json.matchType || (
      json.lead_id && json.contact_id ? 'both' :
      json.lead_id ? 'lead' :
      json.contact_id ? 'contact' : 'none'
    ),
    tags: Array.isArray(json.tags) ? [...json.tags] : [],
    tag_ids: Array.isArray(json.tag_ids) ? [...json.tag_ids] : [],
    tag_objects: Array.isArray(json.tag_objects) ? [...json.tag_objects] : []
  };

  if (!map.has(key)) {
    map.set(key, [entry]);
  } else {
    map.get(key).push(entry);
  }
}

// مرحلة الدمج
const merged = Array.from(map.entries()).map(([folderName, records]) => {
  const leadRecord = records.find(r => r.lead_id);
  const contactRecord = records.find(r => r.contact_id);

  return {
    json: {
      folder_name: folderName,
      lead_id: leadRecord?.lead_id || null,
      contact_id: contactRecord?.contact_id || null,
      matchType: leadRecord && contactRecord ? 'both'
                : leadRecord ? 'lead'
                : contactRecord ? 'contact'
                : 'none',
      all_records: records
    }
  };
});

return merged;

// Function node (n8n)

// مفتاح التجميع = contact_id + document_id (مع fallback للاسم لو مفيش id)
const map = new Map();

const toArr = v => Array.isArray(v) ? v : (v == null ? [] : [v]);
const uniq = arr => [...new Set(arr)];
const mergeObjsUniq = (a = [], b = []) => {
  const s = [...a, ...b].map(o => JSON.stringify(o));
  return [...new Set(s)].map(x => JSON.parse(x));
};

for (const { json } of items) {
  const key = `${json.contact_id ?? json.contact_name ?? 'no_contact'}-${json.document_id ?? 'no_doc'}`;

  if (!map.has(key)) {
    map.set(key, {
      ...json,
      // تأكد أن القوائم Arrays
      tags: toArr(json.tags),
      tag_ids: toArr(json.tag_ids),
      tag_objects: toArr(json.tag_objects),
      phone_values: toArr(json.phone_values),
      email_values: toArr(json.email_values),
    });
  } else {
    const ex = map.get(key);

    // دمج حقول القائمة
    ex.tags = uniq([...toArr(ex.tags), ...toArr(json.tags)]);
    ex.tag_ids = uniq([...toArr(ex.tag_ids), ...toArr(json.tag_ids)]);
    ex.tag_objects = mergeObjsUniq(ex.tag_objects, json.tag_objects);

    ex.phone_values = uniq([...toArr(ex.phone_values), ...toArr(json.phone_values), json.contact_phone].filter(Boolean));
    ex.email_values = uniq([...toArr(ex.email_values), ...toArr(json.email_values), json.contact_email].filter(Boolean));

    // احتفظ بأول قيم غير فاضية لباقي الحقول
    for (const k of [
      'lead_id','lead_name','company_id','company_name',
      'contact_id','contact_name','phone_query',
      'document_id','document_name','tag_id','tag_name',
      'batch_date','batch_time'
    ]) {
      if (ex[k] == null || ex[k] === '') ex[k] = json[k];
    }
  }
}

// احسب الـ matchType لكل مجموعة
const out = [];
for (const obj of map.values()) {
  const hasLead = !!obj.lead_id;
  const hasContact = !!obj.contact_id;
  let matchType = 'none';
  if (hasLead && hasContact) matchType = 'both';
  else if (hasLead) matchType = 'lead';
  else if (hasContact) matchType = 'contact';

  out.push({ json: { ...obj, hasLead, hasContact, matchType } });
}

return out;

return items.map(item => {
  const d = item.json || {};
  const fromNested =
    Array.isArray(d.all_records) && d.all_records[0] ? d.all_records[0] : {};

  // القيم الأساسية مع فُلّباك من السجل المتعشّق
  const folder_name = d.folder_name || fromNested.folder_name || null;
  const folder_Id   = d.folder_Id   || fromNested.folder_Id   || null;

  const company_name =
    d.company_name || d.companyName ||
    fromNested.company_name || fromNested.companyName || null;

  const company_id =
    d.company_id ?? fromNested.company_id ?? null;

  return {
    json: {
      lead_id: d.lead_id ?? null,
      company_id,
      company_name,
      folder_name,
      folder_Id
    }
  };
});
